//-------------------------------------------------------------------------
// 화면로딩시
//------------------------------------------------------------------------
scwin.onpageload = function() {
    try{
        const codeOptions = [
            { grpCd: "SD161", compID: "acb_odrCnclItemCd" }
        ];
        $c.data.setCommonCode(codeOptions);

        // sd_402_01_35t 로직처리
        scwin.repClntNo = $c.data.getParameter("repClntNo") == null ? "" : $c.data.getParameter("repClntNo");
        scwin.clntNo = $c.data.getParameter("clntNo") == null ? "" : $c.data.getParameter("clntNo");
        scwin.clntNm = $c.data.getParameter("clntNm") == null ? "" : $c.data.getParameter("clntNm");
        scwin.mchtOdrKndCd = $c.data.getParameter("mchtOdrKndCd") == null ? "" : $c.data.getParameter("mchtOdrKndCd");
        scwin.mchtOdrKndNm = $c.data.getParameter("mchtOdrKndNm") == null ? "" : $c.data.getParameter("mchtOdrKndNm");
        scwin.mchtOdrNo = $c.data.getParameter("mchtOdrNo") == null ? "" : $c.data.getParameter("mchtOdrNo");
        scwin.mcomOdrNo = $c.data.getParameter("mcomOdrNo") == null ? "" : $c.data.getParameter("mcomOdrNo");
        scwin.logSeq = $c.data.getParameter("logSeq") == null ? "" : $c.data.getParameter("logSeq");
        scwin.type = $c.data.getParameter("type") == null ? "" : $c.data.getParameter("type");

        scwin.hid_odrNo = scwin.mcomOdrNo;
        scwin.hid_repClntNo = scwin.repClntNo;
        scwin.hid_clntNo = scwin.clntNo;
        scwin.hid_clntNm = scwin.clntNm;
        scwin.hid_mchtOdrKndCd = scwin.mchtOdrKndCd;
        scwin.hid_mchtOdrKndNm = scwin.mchtOdrKndNm;
        scwin.hid_mchtOdrNo = scwin.mchtOdrNo;
        scwin.hid_mcomOdrNo = scwin.mcomOdrNo;
        scwin.hid_logSeq = scwin.logSeq;
        scwin.hid_chkReterieve = scwin.type;

        if (acb_ctrtNo.getValue() != "선택") {
            scwin.f_RetrieveCtrtWrkPath(acb_ctrtNo.getValue());
        }

    } catch (e){
        console.log("onpageload: " + e)
    }
};

//-------------------------------------------------------------------------
//scwin.onpageload 후 UDC관련 처리
//-------------------------------------------------------------------------
scwin.onUdcCompleted = async function() {
    try{
        await scwin.f_defaultValue();

        // 탭 선택 호출 35t에서 스크립트 에러로 주석처리함.
        //if(parent.document.readyState  === "interactive" || parent.document.readyState === "complete") 	
        	//$p.parent().scwin.f_selectTabMenu(0); // 상위 Tab 페이지의 초기화가 완료되었을때
        await scwin.f_setSearchData(); // sd_402_01_35t 로직처리
        if(ed_wrkEndHh.getValue().trim()!=""){
            $c.gus.cfEnableObj(ed_wrkEndHh, false);
        }
    } catch (e){
        console.log("onUdcCompleted: " + e)
    }  

};

//-------------------------------------------------------------------------
// 공통코드가 셋팅이 되고 scwin.ondataload 이벤트가 호출
//-------------------------------------------------------------------------
scwin.ondataload = function() { 
};

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_defaultValue = async function() {
    try{
        // DataSet HEADER 정의 - 초기화
        scwin.f_dsMchtOdrKndCdHeader();	// 화주 오더종류
        scwin.f_dsOrderHeader();				// 오더 
        scwin.f_dsOrderQueryConditionHeader();	// 오더 조회조건 - 계약 거래처 조회
        scwin.f_dsLobranQueryConditionHeader();	// 물류점소

        // EDI MAPPING 조회 조건 초기값
        scwin.hid_docCd = scwin.docCd;
        scwin.hid_wrkPlCd = scwin.wrkPlCd;

        ds_ediMappingSearch.set("docCd", scwin.hid_docCd);
        ds_ediMappingSearch.set("wrkPlCd", scwin.hid_wrkPlCd);

        // 조회 조건 초기화
  	    scwin.f_FieldClear();

        lay_selfClsCd.setValue("");	// 자가구분 - 표시

        // 출발일자, 도착일자 초기값 설정
  	    ed_wrkEndDt.setValue(scwin.strCurDate);

        // 오더 담당 정보 설정
        let userName = $c.gus.cfIsNull(scwin.memJson.userNm)? "" : scwin.memJson.userNm;
        let userMpNo = $c.gus.cfIsNull(scwin.memJson.userMpNo)? "" : scwin.memJson.userMpNo;
        ed_txt_odrPicNm.setValue(userName);
        ed_txt_odrPicTelNo.setValue(userMpNo);

        // 로그인 사용자 물류점소 - 영업부서 조회
        ds_lobranQueryCondition.set("deptmentCd", DsConstants.SALES_DEPARTMENT);// 영업부서
        const r = await $c.sbm.execute(sbm_retrieveLobranSales);//tr_retrieveLobranSales.post(); ASIS하단 소스는 콜백처리후로 이동됨.
        scwin.sbm_retrieveLobranSales_submitdone(r);

        //로그인 사용자 물류점소 - 운송부서 조회
        ds_lobranQueryCondition.set("deptmentCd", DsConstants.TRANS_DEPARTMENT);	// 운송부서
        const r1 = await $c.sbm.execute(sbm_retrieveLobranTrans);//tr_retrieveLobranTrans.post(); ASIS하단 소스는 콜백처리후로 이동됨
        scwin.sbm_retrieveLobranTrans_submitdone(r1);

    } catch (e) {
       console.log("f_defaultValue : " + e);
    } 
};

//-------------------------------------------------------------------------
// DataSet Header 정의 - 화주 오더종류
//-------------------------------------------------------------------------
scwin.f_dsMchtOdrKndCdHeader = function() { 
    try{
        ds_mchtOdrKndCd.insertRow(0);
        ds_mchtOdrKndCd.setCellData(0, "osideCd", "");
        ds_mchtOdrKndCd.setCellData(0, "osideCdNm", "선택");

    } catch (e) {
       console.log("f_dsMchtOdrKndCdHeader : " + e);
    } 
};

//-------------------------------------------------------------------------
// DataSet Header 정의 - 오더
//-------------------------------------------------------------------------
scwin.f_dsOrderHeader = function() { 
    try{
        ds_order.insertRow(0);
        ds_order.setRowPosition(0);
    } catch (e) {
       console.log("f_dsOrderHeader : " + e);
    } 
};

//-------------------------------------------------------------------------
// DataSet Header 정의 - 청구 거래처
//-------------------------------------------------------------------------
scwin.f_dsOrderQueryConditionHeader = function() { 
    try{
       //ds_orderQueryCondition.set("bizDivCntrYn", scwin.bizDivCntrYn);
       //ds_orderQueryCondition.set("bizDivBulkYn", scwin.bizDivBulkYn);
       ds_orderQueryCondition.set("bizDivTplYn", scwin.bizDivTplYn);

    } catch (e) {
       console.log("f_dsOrderQueryConditionHeader : " + e);
    } 
};

//-------------------------------------------------------------------------
// DataSet Header 정의 - 물류점소 영업부서 조회조건
//-------------------------------------------------------------------------
scwin.f_dsLobranQueryConditionHeader = function() { 
    try{
       ds_lobranQueryCondition.set("lobranCd", scwin.memJson.lobranCd);
       ds_lobranQueryCondition.set("lobranClsCd", "T");
       ds_lobranQueryCondition.set("deptmentCd", DsConstants.SALES_DEPARTMENT);
       ds_lobranQueryCondition.set("useYn", DsConstants.YN_YES);

    } catch (e) {
       console.log("f_dsLobranQueryConditionHeader : " + e);
    } 
};

//-------------------------------------------------------------------------
// 사용자 물류점소 영업부서 정보 조회 결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieveLobranSales_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

        //ds_lobranSales event=OnLoadCompleted(rowCnt) 물류점소 영업부서 DataSet
        if (ds_lobranSales.getRowCount() > 0){
            ed_bilgLodeptCd.setValue(ds_lobranSales.getCellData(0, "lobranCd"));//ds_lobranSales.NameValue(ds_lobranSales.RowPosition, "lobranCd");
            ed_bilgLodeptCd.hidVal = ds_lobranSales.getCellData(0, "lobranCd");//ds_lobranSales.NameValue(ds_lobranSales.RowPosition, "lobranCd");
            ed_txt_bilgLodeptNm.setValue(ds_lobranSales.getCellData(0, "lobranNm"));//ds_lobranSales.NameValue(ds_lobranSales.RowPosition, "lobranNm");
            ed_txt_bilgLodeptNm.hidVal = ds_lobranSales.getCellData(0, "lobranNm");//ds_lobranSales.NameValue(ds_lobranSales.RowPosition, "lobranNm");
        }
    } catch (e) {
       console.log("sbm_retrieveLobranSales_submitdone : " + e);
    } 
};

//-------------------------------------------------------------------------
// 로그인 사용자 물류점소 - 운송부서 조회 결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieveLobranTrans_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

        //ds_lobranSales ds_lobranTrans event=OnLoadCompleted(rowCnt)
        if (ds_lobranTrans.getRowCount() > 0){
            // 매출부서 설정 <- 운송부서
            ed_sellLodeptCd.setValue(ds_lobranTrans.getCellData(0, "lobranCd"));//ds_lobranTrans.NameValue(ds_lobranTrans.RowPosition, "lobranCd");
            ed_sellLodeptCd.hidVal = ds_lobranTrans.getCellData(0, "lobranCd");//ds_lobranTrans.NameValue(ds_lobranTrans.RowPosition, "lobranCd");
            ed_txt_sellLodeptNm.setValue(ds_lobranTrans.getCellData(0, "lobranNm"));//ds_lobranTrans.NameValue(ds_lobranTrans.RowPosition, "lobranNm");
            ed_txt_sellLodeptNm.hidVal = ds_lobranTrans.getCellData(0, "lobranNm");//ds_lobranTrans.NameValue(ds_lobranTrans.RowPosition, "lobranNm");
        }

        $c.gus.cfEnableKeyData();
	    $c.gus.cfDisableKey();

        // 입력 Object 중 한글입력 항목의 IME Mode를 설정한다. TOBE IME 설정없음.
  	    //cfSetIMEModeActiveObjects([txt_dmndNm, txt_sellLodeptNm, txt_bilgLodeptNm, txt_dptWrkPlNm, txt_arvWrkPlNm, txt_onPicNm, txt_offPicNm, txt_odrPicNm, ta_rmk]);

        // PopUp 이미지 버튼을 비활성화 시킨다.
  	    scwin.f_DisablePopUpObj();

        // 오더 확정 버튼 비활성화
        //$c.gus.cfDisableObjects([btn_CompleteOrder, btn_OrderSheetPrint]);
        //$c.gus.cfDisableObjects([btn_ConfirmOrder]);

        // 오더 확정 버튼 비활성화(ntis기준으로변경)
	    $c.gus.cfDisableObjects([btn_OrderSheetPrint]);
	    //cfDisableObjects([btnConfirmOrder]);

        $c.gus.cfEnableObjects([btn_PopUp1]);

        // 그리드 행추가 / 삭제 /취소 버튼 비활성화
        $c.gus.cfDisableAllBtn();
  	    //$c.gus.cfDisableObjects([btn_Update, btn_Save, btn_Delete]);//$c.gus.cfDisableBtn();

        // 오더 종류에 따른 화면 설정
  	    scwin.f_defaultOdrKndSetting();

        // Tab 오더정보 초기화
	    scwin.f_clearTabOrderInfo();

        $c.gus.cfDisableObjects([tb_order]);

        tbx_totalRows.setValue(0);
        ed_clntNo.focus();

        $p.parent().scwin.hid_frameLoad = "0";

    } catch (e) {
       console.log("sbm_retrieveLobranTrans_submitdone : " + e);
    } 
};

//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
    try{
        //cfEnableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7, img_PopUp8, img_PopUp9, img_PopUp10]);
        $c.gus.cfEnableObjects([btn_PopUp1, btn_PopUp2, btn_PopUp3, btn_PopUp4, btn_PopUp5, btn_PopUp6, btn_PopUp7, btn_PopUp8, ed_wrkStDt, ed_wrkEndDt]);

    } catch (e) {
       console.log("f_EnablePopUpObj : " + e);
    }    
};

//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function () {
    try{
        //cfDisableObjects([img_PopUp1, img_PopUp2, img_PopUp3, img_PopUp4, img_PopUp5, img_PopUp6, img_PopUp7, img_PopUp8, img_PopUp9, img_PopUp10]); //img_PopUp9 : ed_wrkStDt , img_PopUp10 : ed_wrkEndDt
        $c.gus.cfDisableObjects([btn_PopUp1, btn_PopUp2, btn_PopUp3, btn_PopUp4, btn_PopUp5, btn_PopUp6, btn_PopUp7, btn_PopUp8, ed_wrkStDt, ed_wrkEndDt]);

    } catch (e) {
       console.log("f_DisablePopUpObj : " + e);
    }    
