scwin.udc_clntNo_callBackFunc = function (ret) {
    try{
        $c.gus.cfSetReturnValue(ret, ed_clntNo, ed_txt_clntNm );//$c.gus.cfSetReturnValue(ret, ed_clntNo, ed_txt_clntNm ,[scwin.hid_ctrtRepClntNo]); 하위에서 rtnList[2]; //상위거래처코드로 체크로 변경함.

        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        // 거래처 선택시 화주오더종류를 조회한다.
  		if(rtnList != null && rtnList[0] != "N/A"){
            scwin.hid_ctrtRepClntNo = rtnList[2]; //상위거래처코드
            if ($c.gus.cfIsNull(scwin.hid_ctrtRepClntNo))
            scwin.hid_ctrtRepClntNo = ed_clntNo.getValue();

            const params = {
                docCd      : scwin.hid_docCd , //문서코드
                clntNo      : scwin.hid_ctrtRepClntNo , //거래처번호
                wrkPlCd      : scwin.hid_wrkPlCd , //작업장코드
                itemCd      : scwin.hid_itemCd , //항목코드
                osideCd      : scwin.hid_osideCd , //외부코드
                ctrtNo      : acb_ctrtNo.getValue() , //계약번호
            };
            //데이터셋에 정보설정
            ds_ediMappingSearch.setJSON(params);
            $c.sbm.execute(sbm_reterieveMchtOdrKnd);
        }else{
            scwin.hid_ctrtRepClntNo = "";
        }

    } catch (e) {
       console.log("udc_clntNo_callBackFunc : " + e);
    }     
};

//-------------------------------------------------------------------------
// 요청거래처 조회결과 콜백
//-------------------------------------------------------------------------
scwin.ed_reqClntNo_callBackFunc = function(ret) {
    try{

        // 선언부
        let rtnList = new Array();  // 공통POP-UP -> 요청화면
        rtnList = ret ;

        if ( rtnList != null) {
            if(rtnList[0].trim() != "N/A"){
                //return value Assign
                let chkValue = false;

                for( let idx = 0 ; idx < ds_reqClntNo.getRowCount() ; idx++){
                    if (rtnList[0] == ds_reqClntNo.getCellData( idx,  "clntNo" )){
                        if(idx>0){
                            acb_reqClntNm.setSelectedIndex(idx-1);//lc_reqClntNm.Index = idx-1;	//위치 이동
                        }else {
                            acb_reqClntNm.setSelectedIndex(idx);//lc_reqClntNm.Index = idx;	//위치 이동
                        }
                        chkValue = true;
                        scwin.hid_chkReqClntNo = rtnList[0];	//요청 거래처코드
                        break;
                    }
                }

                if(!chkValue) {
                    let row = ds_reqClntNo.insertRow();
                    ds_reqClntNo.setCellData( row,  "clntNo", rtnList[0]) ;	//실화주코드
                    ds_reqClntNo.setCellData( row,  "clntNm" , rtnList[1]) ;//실화주명
                    acb_reqClntNm.setValue(rtnList[0])
                //    acb_reqClntNm.setSelectedIndex(row-1);//lc_reqClntNm.Index = row-1;	//위치 이동
                    ed_reqClntNo.setValue(rtnList[0]);	//요청 거래처코드
                    ed_reqClntNo.hidVal = rtnList[0];	//요청 거래처코드
                    scwin.hid_chkReqClntNo = rtnList[0];	//요청 거래처코드
                }	
            } else {
                ed_reqClntNo.setValue("");	//요청 거래처코드
                ed_reqClntNo.hidVal = "";	//요청 거래처코드
                scwin.hid_chkReqClntNo = "";	//요청 거래처코드
                acb_reqClntNm.setValue("");//lc_reqClntNm.Index = -1;

               // ed_reqClntNo.setValue(ed_reqClntNo.hidVal);
            }			
        } else {
            ed_reqClntNo.setValue("");	//요청 거래처코드
            ed_reqClntNo.hidVal = "";	//요청 거래처코드
            scwin.hid_chkReqClntNo = "";	//요청 거래처코드
            acb_reqClntNm.setValue("");//lc_reqClntNm.Index = -1;
        }

    } catch (e) {
       console.log("ed_reqClntNo_callBackFunc : " + e);
    }     
};

