scwin.sbm_reterieveMchtOdrKnd_submitdone = async function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        if( ds_mchtOdrKndCd.getRowCount() == 0 ){
            $c.gus.cfAlertMsg($c.data.getMessage("%1의 "+MSG_CM_ERR_003,"화주오더종류"));
        }else{
            ds_mchtOdrKndCd.insertRow(0);
            ds_mchtOdrKndCd.setCellData(0, "osideCd", "");
            ds_mchtOdrKndCd.setCellData(0, "osideCdNm", "선택");

        }
    } catch (e) {
       console.log("sbm_reterieveMchtOdrKnd_submitdone " + e);
    }
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    try{
        let ctrtRepClntNo = scwin.hid_ctrtRepClntNo;
        let clntNo = ed_clntNo.getValue().replace(/\s*$/, '');
        let mchtOdrKndCd  = acb_mchtOdrKndCd.getValue();
        let mchtOdrNo = ed_mchtOdrNo.getValue().replace(/\s*$/, '');
        let mcomOdrNo = ed_mcomOdrNo.getValue().replace(/\s*$/, '');

        if ($c.gus.cfIsNull(mcomOdrNo)){
            if(!$c.gus.cfIsNull(clntNo)){	// 계약거래처가 지정된 경우
                if($c.gus.cfIsNull(mchtOdrKndCd)){
                    $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_002,"화주오더종류"));
                    acb_mchtOdrKndCd.focus();
                    return false;
                }

                if($c.gus.cfIsNull(mchtOdrNo)){
                    $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_002,"화주오더번호"));
                    ed_mchtOdrNo.focus();
                    return false;
                }

            }else{
                $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_002,"계약거래처 또는 당사오더번호"));
                ed_clntNo.focus();
                return false;
            }
        } else {
            let ret = await $c.gus.cfValidate([ed_mcomOdrNo]);
            if (!ret) {
                return false;
            }
        }

        scwin.acb_ctrtNo_check =""; //관리대상이므로 오더등록 체크 초기화
        // DataSet 초기화
	    scwin.f_clearDataSetAll();

        const params = {
            repClntNo   : scwin.hid_ctrtRepClntNo ,
            docCd       : scwin.hid_docCd ,
            wrkPlCd     : scwin.hid_wrkPlCd ,
            itemCd      : scwin.hid_itemCd ,
            osideCd     : scwin.hid_osideCd ,
        };
        //데이터셋에 조회조건 정보(히든 값) 추가설정
        ds_orderSearch.setJSON(params);

        const r = await $c.sbm.execute(sbm_reterieve);
        if(r.responseJSON.resultDataSet[0].Code == -1) {
         //   await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
        } else if (r.responseJSON.resultDataSet[0].Msg == "SUCC") {
            scwin.sbm_reterieve_submitdone(r);
        }
    } catch (e) {
       console.log("f_Retrieve " + e);
    }
};

//-------------------------------------------------------------------------
// DataSet 초기화 처리 : 전체 DataSet 을 초기화 한다.
//-------------------------------------------------------------------------
scwin.f_clearDataSetAll = async function () {
    try{

        //scwin.ds_shipmentIndicationOrder_onrowpositionchange(); //TOBE 오더요청 기본정보 초기화

        // 오더기본정보 DataSet 초기화
        ds_order.removeAll();
        ds_order.insertRow(0);
        ds_order.setRowPosition(0);

        if (scwin.acb_ctrtNo_check !="Y"){//TOBE 관리대상이므로 오더등록 불가시 예외처리 추가
            ds_shipmentIndicationOrder.removeAll();
            ds_shipmentIndicationCommodity.removeAll();
        }

        // 계약 거래처 정보 (ds_retrieveCtrtClnt) DataSet 초기화
		scwin.f_clearDataSetRetrieveCtrtClnt();

        // 계약번호 (ds_ctrtNo) DataSet 초기화
		ds_ctrtNo.removeAll();

        // 요청 거래처 정보 (ds_reqClntNo) DataSet 초기화
		ds_reqClntNo.removeAll();

        // 청구 거래처 정보 (ds_bilgClntNo) DataSet 초기화
		ds_bilgClntNo.removeAll();

        // HIDDEN 값 초기화
        if (scwin.acb_ctrtNo_check !="Y"){//TOBE 관리대상이므로 오더등록 불가시 예외처리 추가
		    scwin.f_clearData();
        }

    } catch (e) {
       console.log("f_clearDataSetAll " + e);
    }
};     

