//-------------------------------------------------------------------------
// Data 초기화 (HTML INPUT)
//-------------------------------------------------------------------------
scwin.f_clearData = function () {
    try{
        // Order Master DataSet 값 초기화
        for (let i=0; i< ds_order.getTotalCol(); i++) {
            ds_order.setCellData(ds_order.getRowPosition(), ds_order.getColumnID(i), "");
        }

        ed_txt_bilgLodeptNm.setValue("");
        ed_txt_sellLodeptNm.setValue("");
        ed_txt_dptWrkPlNm.setValue("");
        ed_txt_arvWrkPlNm.setValue("");

        ed_txt_dptWrkPlNm.hidVal = "";	  	
        ed_txt_arvWrkPlNm.hidVal = "";

        scwin.hid_odrKndCd = acb_odrKndCd.getValue();// 오더종류 lc_odrKndCd.ValueOfIndex("cd", lc_odrKndCd.Index);
        //ds_order hidden 정보 바인드
        ds_order.setCellData(ds_order.getRowPosition(), "odrKndCd", scwin.hid_odrKndCd);//오더종류코드

