//-------------------------------------------------------------------------
// 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_reterieve_submitdone = async function (e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) {
            scwin.f_noResultDataClear();//입력부정보 초기화
            return; //onFail
        }

        ds_shipmentIndicationOrder.setJSON(e.responseJSON.OUT_DS1);
        ds_shipmentIndicationCommodity.setJSON(e.responseJSON.OUT_DS2);
        ds_order.setJSON(e.responseJSON.OUT_DS3);
        ds_orderCommodity.setJSON(e.responseJSON.OUT_DS4);
        ds_ctrtNo.setJSON(e.responseJSON.OUT_DS5);
        ds_reqClntNo.setJSON(e.responseJSON.OUT_DS6);
        ds_bilgClntNo.setJSON(e.responseJSON.OUT_DS7);
        ds_wrkPatternCd.setJSON(e.responseJSON.OUT_DS8);
        ds_odrKndCd.setJSON(e.responseJSON.OUT_DS9.sort((a, b) => {
            if (a.cd !== b.cd) {
                return a.cd.localeCompare(b.cd);
            }
            if (a.cdNm.length !== b.cdNm.length) {
                return a.cdNm.length - b.cdNm.length; 
            }
            return b.cdNm.localeCompare(a.cdNm);
        }));


        //TOBE 추가 데이터셋의 기본 포지션 정보 설정
        if (ds_shipmentIndicationOrder.getRowCount() > 0) {
         //   ds_shipmentIndicationOrder.unbind("onrowpositionchange");
            ds_shipmentIndicationOrder.setRowPosition(0);
            await scwin.ds_shipmentIndicationOrder_onrowpositionchange(); 
           // ds_shipmentIndicationOrder.bind("onrowpositionchange", "scwin.ds_shipmentIndicationOrder_onrowpositionchange");

        }

        if (ds_shipmentIndicationCommodity.getRowCount() > 0) {
            ds_shipmentIndicationCommodity.setRowPosition(0);
        }

        if (ds_order.getRowCount() > 0) {
            ds_order.setRowPosition(0);
            scwin.reterieveOrderYn = "Y";
        }else{
            scwin.reterieveOrderYn = "N";
        }
        if (ds_orderCommodity.getRowCount() > 0) ds_orderCommodity.setRowPosition(0);
        if (ds_reqClntNo.getRowCount() > 0) ds_reqClntNo.setRowPosition(0);
        if (ds_bilgClntNo.getRowCount() > 0) ds_bilgClntNo.setRowPosition(0);
        if (ds_wrkPatternCd.getRowCount() > 0) ds_wrkPatternCd.setRowPosition(0);
        if (ds_odrKndCd.getRowCount() > 0) ds_odrKndCd.setRowPosition(0);

        //ASIS 데이터바인드 처리 Start (특정결과시 데이터가 지워지는 로직으로 바인드를 직접처리) : ds_order에서 값 존재하는 경우 재매핑 처리
