                $c.gus.cfEnableObjects([btn_OrderSheetPrint]);
            else
                $c.gus.cfDisableObjects([btn_OrderSheetPrint]);

            //TOBE 관리대상이므로 오더등록 데이터인경우에만 ASIS처럼 Sheet 발행 버튼비활성화 수정버튼이 보이도록 처리.

            if ( scwin.acb_ctrtNo_check = "Y") {
            //    $c.gus.cfEnableObjects([btn_Update]);
            }    


       //     scwin.hid_odrKndCd = ds_order.getCellData(ds_order.getRowPosition(), "odrKndCd");	// 오더 종류 설정
            ds_order.setCellData(ds_order.getRowPosition(), "odrKndCd", scwin.hid_odrKndCd);
            acb_odrKndCd.setValue(ds_order.getCellData(ds_order.getRowPosition(), "odrKndCd")); //lc_odrKndCd.IndexOfColumn("cd", ds_order.getCellData(ds_order.getRowPosition() "odrKndCd"));
            scwin.acb_odrKndCd_onviewchange();
        } //if(ds_order.getRowCount() > 0){

    } catch (e) {
