//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
    try{

        let v_logSeq = "";
        let i = 0;
        let v_row = 0;

        // (ntis기준으로변경)
        // 한진오더는 오더확정 불가능.
        if (ds_shipmentIndicationOrder.getCellData(0, "tplcoCls") == "H") {
            $c.win.alert("한진 오더입니다.");
            return false;
        }

        if (ds_shipmentIndicationOrder.getCellData(0, "tplcoCls") == "C") {
            $c.win.alert("대한통운 오더입니다.");
            return false;
        }

        if($c.gus.cfIsNull(scwin.hid_repClntNo)) scwin.hid_repClntNo = scwin.hid_ctrtRepClntNo;

        scwin.f_ds_orderSetting();//TOBE ds_order 정보 바인드 처리
        console.log("nam 오더 조회후2-1 : " + ds_order.getRowStatus(ds_order.getRowPosition()) );

        scwin.f_setDisplayOdrKndCd(acb_odrKndCd.getValue()); //TOBE 강제처리. lc_odrKndCd event=OnSelChange()

        // 작업구분에 따른 확인 
        if(scwin.hid_odrJobType == DGauceConstants.TB_JOB_INSERT){
            if(ds_order.getModifiedIndex().length==0){
                $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_001,"오더기본정보"));    
                return false;
            }

            if(ds_orderCommodity.getModifiedIndex().length==0){
                $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_001,"오더품목정보"));    
                return false;
            }

            /*20160126 화물위탁증 관련 추가*/ // (ntis기준으로변경)
            ds_order.setCellData(0, "trnsRealMchtClntNm", "크나우프석고보드"); 
            ds_order.setCellData(0, "trnsRealMchtClntTelNo", "041-351-3315"); 

            sbm_save.action = "/ncall.ds.sd.odrmgnt.odrreg.RegistShipmentIndicationOrderRequestCMD.do";

            // 오더요청 기본정보 Update 설정
            v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");
            v_row = 0;

            for (i=0; i< ds_shipmentIndicationOrder.getRowCount(); i++) {
                if(v_logSeq >= ds_shipmentIndicationOrder.getCellData(i, "logSeq")){
                    ds_shipmentIndicationOrder.setCellData(i, "rowStatus", DGauceConstants.TB_JOB_UPDATE);
                    ds_shipmentIndicationOrder.setCellData(i, "wrkStDt", ed_wrkStDt.getValue());// 출발일자 설정
                    ds_shipmentIndicationOrder.setCellData(i, "wrkStHh", ed_wrkStHh.getValue());// 출발시간 설정
                    ds_shipmentIndicationOrder.setCellData(i, "wrkEndDt", ed_wrkEndDt.getValue());// 도착일자 설정
                    ds_shipmentIndicationOrder.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue());// 도착시간 설정

                }else{
                    break;
                }

                // 출발작업장코드 자동 설정
			    if($c.gus.cfIsNull(ds_orderCommodity.getCellData(i, "dptWrkPlCd").trim())) ds_orderCommodity.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
                // 도착작업장코드 자동 설정
                if($c.gus.cfIsNull(ds_orderCommodity.getCellData(i, "arvWrkPlCd").trim()))	ds_orderCommodity.setCellData(i, "arvWrkPlCd",ed_arvWrkPlCd.getValue().trim());

            }

            // 품명 1건인 경우 합적할수 없습니다.
            if(ds_orderCommodity.getRowCount() == 1 && rd_coshippingYn.getValue() == "1"){
                $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_041,"오더품목정보가 1건인 경우", "합적"));    
                return false;
            }

        } else {
	 	    // UPDATE
            if(ds_order.getModifiedIndex().length==0 && ds_orderCommodity.getModifiedIndex().length==0){
                $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_001,"오더정보"));    
                return false;
            }

            // 특이사항 수정추가(20150712 서근원) (ntis기준으로변경)
	        ds_shipmentIndicationOrder.setCellData(0, "unqItm", ds_order.getCellData(0, "rmk"));

            sbm_save.action = "/ncall.ds.sd.odrmgnt.odrreg.UpdateShipmentIndicationOrderRequestCMD.do";

            // 오더요청 기본정보 Update 설정
            v_logSeq = ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "logSeq");

            for (i=0; i< ds_shipmentIndicationOrder.getRowCount(); i++) {
                if(v_logSeq >= ds_shipmentIndicationOrder.getCellData(i, "logSeq")){

                    if(v_logSeq == ds_shipmentIndicationOrder.getCellData(i, "logSeq")){

                        ds_shipmentIndicationOrder.setCellData(i, "rowStatus" , DGauceConstants.TB_JOB_UPDATE);
                    } else if(!$c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(i, "mcomOdrNo"))){
                        //ds_shipmentIndicationOrder.setCellData(i, "rowStatus") = DGauceConstants.TB_JOB_UPDATE;
                    } else {
                        $c.gus.cfAlertMsg("이전 오더요청 오더에 대한 작업이 진행되지 않았습니다. ");
                        ds_shipmentIndicationOrder.setRowPosition(i);//ds_shipmentIndicationOrder.RowPosition = i;
                        return false;
                    }
                } else {
	    		    break;
                }
            }

            // 품명 정보 변경 내역 - 확인
	        for(let j = 0; j < ds_orderCommodity.getRowCount(); j++){
                // (ntis기준으로변경)
                ds_orderCommodity.setCellData(j, "rmk", ds_orderCommodity.getCellData(j, "rmk") + " "); 

                // 출발일자/시간, 도착일자/시간 변경시 품명 작업시작일자/시간, 작업완료일자/시간 설정
                if(ds_order.getCellData(ds_order.getRowPosition(), "wrkStDt") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkStDt")
                    || ds_order.getCellData(ds_order.getRowPosition(), "wrkStHh") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkStHh")
                    || ds_order.getCellData(ds_order.getRowPosition(), "wrkEndDt") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkEndDt")
                    || ds_order.getCellData(ds_order.getRowPosition(), "wrkEndHh") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "wrkEndHh")){

                        // 품명 데이터 셋에서 해당 품명을 찾아 정보를 변경
				        ds_orderCommodity.setCellData(j, "wrkStDt", ed_wrkStDt.getValue()); //작업시작일자
                        ds_orderCommodity.setCellData(j, "wrkStHh", ed_wrkStHh.getValue()); //작업시작시간
                        ds_orderCommodity.setCellData(j, "wrkEndDt", ed_wrkEndDt.getValue()); //작업종료일자
                        ds_orderCommodity.setCellData(j, "wrkEndHh", ed_wrkEndHh.getValue()); //작업종료시간
                }

                // 출발지 정보 변경시 오더품명 출발지 정보 변경
		        if(ds_order.getCellData(ds_order.getRowPosition(), "dptWrkPlCd") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "dptWrkPlCd")){
                    // 출발작업장코드 자동 설정
				    if($c.gus.cfIsNull(ds_orderCommodity.getCellData(j, "dptWrkPlCd").trim())) ds_orderCommodity.setCellData(j, "dptWrkPlCd", ed_dptWrkPlCd.egtValue().trim());
                }

                // 도착지 정보 변경시 오더품명 도착지 정보 변경
                if(ds_order.getCellData(ds_order.getRowPosition(), "arvWrkPlCd") != ds_order.getOriginalCellData(ds_order.getRowPosition(), "arvWrkPlCd")){
                    // 출발작업장코드 자동 설정
				    if($c.gus.cfIsNull(ds_orderCommodity.getCellData(j, "arvWrkPlCd").trim())) ds_orderCommodity.setCellData(j, "arvWrkPlCd", ed_arvWrkPlCd.egtValue().trim());
                }
            }
        }

        scwin.tplCommCdChkCallBack = 0; //재귀처리용 기본정보
      //  await scwin.f_tplCommCdCheck(); //자재마스터 상위 존재여부 체크 , 다음프로세스는 TOBE 콜백처리 이후로 이동됨.
        for(let p = 0; p <= ds_shipmentIndicationCommodity.getRowCount(); p++){
            if(await scwin.f_tplCommCdChk(p)){ 
                return;
            }
        }


        if (ds_shipmentIndicationCommodity.getRowCount() > 0) {
            var ctrtWrkPathSeq = 0 ;
            for (var ii = 0; ii < ds_shipmentIndicationCommodity.getRowCount() ; ii++) {
                if (ds_shipmentIndicationCommodity.getCellData(ii, "ctrtWrkPathSeq") > 0) {   
                    ctrtWrkPathSeq = ds_shipmentIndicationCommodity.getCellData(ii, "ctrtWrkPathSeq");
                    break;
                }
            }

            if(ctrtWrkPathSeq == 0) {
                await $c.gus.cfAlertMsg(MSG_CM_WRN_007, new Array("작업경로"));
                return ;
            } else {
                for (var idx = 0 ; idx < ds_shipmentIndicationCommodity.getRowCount(); idx++){
                    ds_shipmentIndicationCommodity.setCellData(idx, "ctrtWrkPathSeq", ctrtWrkPathSeq);
                }
            }

            for (var idx = 0; idx < ds_shipmentIndicationCommodity.getRowCount(); idx++) {
                for (var commIdx = 0; commIdx < ds_orderCommodity.getRowCount(); commIdx++) {
                    if (ds_orderCommodity.getCellData(commIdx, "mgntSeq") == ds_shipmentIndicationCommodity.getCellData(idx, "mgntSeq")) {
                        ds_orderCommodity.setCellData(commIdx, "ctrtWrkPathSeq", ds_shipmentIndicationCommodity.getCellData(idx, "ctrtWrkPathSeq"));    // 계약작업경로순번
                        ds_orderCommodity.setCellData(commIdx, "ctrtWrkPathNm", ds_shipmentIndicationCommodity.getCellData(idx, "ctrtWrkPathNm"));      // 계약작업경로
                    }
                }
            }
        }

        /* 만약에 계약작업경로가 0으로 남아 있는지 여부 확인하여 1번품명의 계약작업경로로 셋팅 */
        for (var ctrtidx = 1 ; ctrtidx <= ds_orderCommodity.getRowCount(); ctrtidx++) {
            if (ds_orderCommodity.getCellData(ctrtidx, "ctrtWrkPathSeq") == 0) {
                ds_orderCommodity.setCellData(ctrtidx, "ctrtWrkPathSeq", ds_shipmentIndicationCommodity.getCellData(0, "ctrtWrkPathSeq"));    // 계약작업경로순번
                ds_orderCommodity.setCellData(ctrtidx, "ctrtWrkPathNm", ds_shipmentIndicationCommodity.getCellData(0, "ctrtWrkPathNm"));      // 계약작업경로
            } 
        }

        let vaildResutl = await scwin.f_validChk();
        console.log("Fin. vaildResutl" + vaildResutl);

        if (vaildResutl) {
            // 삭제 시에 귀책사유 선택 여부 확인
    	    if(lay_stsClsCd.getValue() =="D" && acb_odrCnclItemCd.getValue() ==""){
                $c.win.alert("귀책사유를 선택해 주십시요.");
    		    return false;
            }

            if(await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_001, "오더정보"))) { //저장하시겠습니까?
                //Eidt 속성을 Disable로  변경한다.
                $c.gus.cfDisableKeyData();
                $c.gus.cfDisableObjects([btn_Update, btn_Save, btn_Delete]);//cfDisableAllBtn();

                $c.sbm.execute(sbm_save);
            }
        }

    } catch (e) {
       console.log("f_Save " + e);
    }
};

