//-------------------------------------------------------------------------
// 자재마스터 상위 존재여부 체크 UDC
//-------------------------------------------------------------------------
scwin.f_tplCommCdChk = async function (row) {
    try{
        scwin.clntNo = ds_shipmentIndicationOrder.getCellData(0, "repClntNo");
        scwin.clntCommCd = ds_shipmentIndicationCommodity.getCellData(row, "clntCommCd");

        if(scwin.clntNo == ""){
            return;
        }
        if(scwin.clntCommCd == ""){
            return;
        }

        //rtnList = cfCommonPopUp('retrieveTplCommCd',"사용안함","사용안함","T",null,null,null,null,clntNo+","+clntCommCd,null,null,null,null,null,null,null,"T"); // 거래처
        udc_comCodeGrid.setSelectId('retrieveTplCommCd');
        var rtnList = await udc_comCodeGrid.cfCommonPopUpAsync(scwin.udc_tplCommCd_callBackFunc // 콜백 함수
                        , '사용안함'              // 화면에서의 ??? Code Element의 Value
                        , '사용안함'              // 화면에서의 ??? Name Element의 Value
                        , 'T'                     // 결과가 1건 일때 원도우를	AutoClose 여부(T:Close,F:Opened)
                        , null                            // 검색 결과 컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                        , null                            // Title순서
                        , null                            // 보여주는 각 컬럼들의 폭
                        , null                            // 컬럼중에서 숨기는 컬럼 지정
                        , scwin.clntNo+","+scwin.clntCommCd                            // SQL절의 WHERE절에 원하는 조건을 선택함 MAX:8개까지 가능
                        , null                            // POP-UP뛰을때 원도우의 사용자 정의 폭
                        , null                            // POP-UP뛰을때 윈도우의 사용자 정의 높이
                        , null                            // 윈도우 위치 Y좌표
                        , null                            // 윈도우 위치 X좌표
                        , null                            // 중복체크여부	("F")
                        , null                            // 전체검색허용여부	("F")
                        , null                            // POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번검색Nm")
                        );

        let returnFlag = false;
        scwin.tplCommCdCallBack = rtnList[0];

        console.log("tplCommCdCallBack :::" + scwin.tplCommCdCallBack + ",: scwin.tplCommCdChkCallBack : " + scwin.tplCommCdChkCallBack);

        //0번째 정보를 받아오지 못하고 있음.
        if(scwin.tplCommCdCallBack == '0'){ //자재번호가 존재하지 않을경우
            await $c.win.alert("자재번호 : "+scwin.clntCommCd+" 은(는) 존재하지 않습니다.<br/><br/>관리자에게 문의하여 주십시오.");
            returnFlag = true;
        }else if(scwin.tplCommCdCallBack == '1'){ //자재번호 존재하지만 상위코드 없는경우
            await $c.win.alert("자재번호 : "+scwin.clntCommCd+" 은(는) 자재마스터 상위코드가 없습니다.<br/><br/>등록해 주십시오.");
            returnFlag = false;
            //$c.win.alert("자재번호 : "+scwin.clntCommCd+" 은(는) 자재마스터 상위코드가 없습니다.<br/><br/>\'확인\' 버튼을 누르면  등록팝업이 뜹니다.<br/><br/>등록해 주십시오.");
            //let boolTplCommCd = await scwin.f_tplCommCdPop(scwin.clntNo,scwin.clntCommCd);
            //return boolTplCommCd;
        }else if(scwin.tplCommCdCallBack == '2'){ //정상일 경우
            returnFlag = false;
        }else{
            await $c.win.alert("더이상 진행할 수 없읍니다. 관리자에게 문의 하십시오.");
            returnFlag = true;
        }
        /*
        //TOBE 콜백의 경우 다음프로세스로 진행되어 ds_shipmentIndicationCommodity 수만큼 재귀처리하여 체크한다. 
        if (returnFlag ==  true){
            return true;
        }else{
            scwin.tplCommCdChkCallBack = scwin.tplCommCdChkCallBack + 1 ;
            if (scwin.tplCommCdChkCallBack != ds_shipmentIndicationCommodity.getRowCount()){
                scwin.f_tplCommCdChk(scwin.tplCommCdChkCallBack);
            }    

            if (scwin.tplCommCdChkCallBack == ds_shipmentIndicationCommodity.getRowCount()){
                console.log("다음로직으로 넘어가야 함. 체크종료");
              //  scwin.f_validChkFnc();
            }    
        } */
    } catch (e) {
       console.log("f_tplCommCdChk " + e);
    }
};

