//-------------------------------------------------------------------------
// 저장전 validation check - 오더 정보
//-------------------------------------------------------------------------
scwin.f_validChk = async function () {
    try{
        let ret = false;
        if (scwin.vaildObj !=""){
            //ret = await $c.gus.cfValidate([scwin.vaildObj]); TOBE 변수로 처리되지 않아 값 존재여부만 체크후 아래와 같이 전체 체크로 변경함.
            ret = await $c.gus.cfValidate([
                acb_odrKndCd, acb_ctrtNo, ed_reqClntNo, ed_bilgClntNo, 
                ed_sellLodeptCd, ed_bilgLodeptCd, ed_dptWrkPlCd , 
                ed_arvWrkPlCd, ed_wrkStDt, ed_wrkStHh, 
                ed_wrkEndDt, ed_wrkEndHh, ed_txt_onPicNm,
                ed_txt_offPicNm, ed_txt_odrPicNm
            ], null, true);
        }else{
            ret = true;
        }

        if (ret) {
            if (td_wrkEndDtHh_02.getStyle("display") == "inline" || td_wrkEndDtHh_02.getStyle("display") == "block" || td_wrkEndDtHh_02.getStyle("display") == "flex"){

                // 출발작업일자가 도착작업일자보다 큰 경우
                if( ed_wrkStDt.getValue().trim() > ed_wrkEndDt.getValue().trim() ){
                    await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_048,"화주오더종류","도착작업일자"));
                    ed_wrkEndDt.focus();
                    return false;
                }

                // 출발작업시간이 도착작업시간보다 큰 경우
                if( ed_wrkStDt.getValue().trim() ==  ed_wrkEndDt.getValue().trim() && ed_wrkStHh.getValue().trim() >= ed_wrkEndHh.getValue().trim() ){
                    await $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_057,"도착작업시간","출발작업시간"));
                    ed_wrkEndHh.focus();
                    return false;
                }
            }

            // ntis기준으로변경
            // 상차, 하차, 오더 담당 전화번호 유효성 확인
            if(tr_picNm_picTelNo.getStyle("display") != "none"){
                // 상차
                if (ed_txt_onPicTelNo.getValue() != "" && !dscommon.cf_PhoneCheck(ed_txt_onPicTelNo))
                    return false;

                // 하차
  			    // 20180524 원래 telNo , 뺀거 걸로 유효성검사 후 다시 재 셋팅
                var offPicTelNo2  = ed_txt_offPicTelNo.getValue();
  			    ed_txt_offPicTelNo.setValue(ed_txt_offPicTelNo.getValue().replace(/,/gi,""));
                if (ed_txt_offPicTelNo.getValue() != "" && !dscommon.cf_PhoneCheck(ed_txt_offPicTelNo))
                    return false;

                ed_txt_offPicTelNo.setValue(offPicTelNo2);
                if (offPicTelNo2 == "") {
                    $c.win.alert("하차담당자 전화번호를 넣어주세요.");
                    return false;
                }

                // 오더
                if (ed_txt_odrPicTelNo.getValue() != "" && !dscommon.cf_PhoneCheck(ed_txt_odrPicTelNo))
                    return false;  				  				
            }

            for (let i=0; i< ds_orderCommodity.getRowCount(); i++) {
                // 수량, 중량, CBM 중 한가지는 입력하여야 합니다.
	  		    if(ds_orderCommodity.getCellData(i, "qty") == "0" 
                    && ds_orderCommodity.getCellData(i, "grossWt") == "0"
                    && ds_orderCommodity.getCellData(i, "cbm") == "0"){
                        $c.gus.cfAlertMsg("수량, 중량, CBM 중 한가지는 입력하셔야 합니다.");
                        ds_orderCommodity.setRowPosition(i);
                        //gr_orderCommodity.SetColumn("qty");	
					    return false;
                }
                // 품명의 출발일자, 출발시간, 도착일자, 도착시간 정보를 오더 출발일시, 도착일시로 설정한다.
  			    ds_orderCommodity.setCellData(i, "wrkStDt", ed_wrkStDt.getValue());
                ds_orderCommodity.setCellData(i, "wrkStHh", ed_wrkStHh.getValue());
                ds_orderCommodity.setCellData(i, "wrkEndDt", ed_wrkEndDt.getValue());
                ds_orderCommodity.setCellData(i, "wrkEndHh", ed_wrkEndHh.getValue());

                // 출발작업장코드, 도착작업장코드 자동 설정
                ds_orderCommodity.setCellData(i, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
                ds_orderCommodity.setCellData(i, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

                // 필수 항목 확인 - 품명 정보 설정 확인
                if ($c.gus.cfIsNull(ds_orderCommodity.getCellData(i, "commCd"))){
                    $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_WRN_018,"품명","EDI MAPPING 정보"));
                    return false;
                }
            }
            return true;
        } else{
            return false;
        }

    } catch (e) {
       console.log("f_validChk " + e);
    }
};

