scwin.f_DptDtSet1 = function () {
    try{
        let sDate = ed_wrkEndDt.getValue().trim(); 
        let yyyy = sDate.substr(0,4);
        let MM = parseInt(sDate.substr(4,2),10) - 1;
        let dd = sDate.substr(6,2);	

        var prevday = new Date(yyyy,MM,dd).before(0, 0, 1).format("YYYYMMDD");

        ds_holiday_Search.set("prevday", prevday);
        $c.sbm.execute(sbm_holiday);

    } catch (e) {
       console.log("f_DptDtSet1 " + e);
    }
};

