//-------------------------------------------------------------------------
// ASIS for=ds_shipmentIndicationOrder event=OnRowPosChanged(row)
//-------------------------------------------------------------------------
scwin.ds_shipmentIndicationOrder_onrowpositionchange = async function (info) {
    try{

        if (ds_shipmentIndicationOrder.getRowCount() > 0){
            let row = ds_shipmentIndicationOrder.getRowPosition();

