                ds_shipmentIndicationCommodity.setColumnFilter( {type:'row', colIndex:'mchtOdrNo', key:v_mchtOdrNo, condition:'and'});
                ds_shipmentIndicationCommodity.setColumnFilter( {type:'row', colIndex:'logSeq', key:v_logSeq, condition:'and'});

            }else{
