//-------------------------------------------------------------------------
// TOBE 계약 거래처 조회 (ASIS 데이터 Bind + tr_retrieveCtrtClnt)
//-------------------------------------------------------------------------
scwin.f_retrieveCtrtClnt = async function () {
    try{

        const params = {
            ctrtClntNo      : scwin.hid_ctrtClntNo , 
            bizDivCntrYn    : scwin.hid_bizDivCntrYn , 
            bizDivBulkYn    : scwin.hid_bizDivBulkYn ,
        };
        //데이터셋에 정보설정
        ds_retrieveCtrtClnt.setJSON(params);
        const r = await $c.sbm.execute(sbm_retrieveCtrtClnt);
        scwin.sbm_retrieveCtrtClnt_submitdone(r);
    } catch (e) {
       console.log("f_retrieveCtrtClnt " + e);
    }
};

//-------------------------------------------------------------------------
// 계약 거래처 조회 결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieveCtrtClnt_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        ds_ctrtNo.setJSON(e.responseJSON.OUT_DS1);
    } catch (e) {
       console.log("sbm_retrieveCtrtClnt_submitdone " + e);
    }
};

//-------------------------------------------------------------------------
// 시간(HHmm) 형식의 값인지 확인
//-------------------------------------------------------------------------
scwin.isHHmm = function (sTime) {
    let flag = true;
    try {
        if (sTime.length != 4) {
            return false;
        }
        const h1 = parseInt(sTime.substring(0, 2), 10);
        const t1 = parseInt(sTime.substring(2, 4), 10);

        if (isNaN(h1) || isNaN(t1))
            flag = false;

        if (h1 + t1 != "") {
            if (h1 < 0 || h1 > 24) {
                flag = false;
            } else if (h1 == 24) {
                if (typeof timeChk == "boolean" && !timeChk)
                    flag = false;
                if (t1 > 0)
                    flag = false;
            }
            if (t1 < 0 || t1 > 59)
                flag = false;
        }
    } catch (ex) {
        console.error(ex);
        flag = false;
    }
    return flag;
};

