                        ds_orderCommodity.setCellData(oc_row, "bizLongCd", ds_shipmentIndicationCommodity.getCellData(i, "bizLongCd")); // 사업장코드
                        ds_orderCommodity.setCellData(oc_row, "tplArvNmCmpy", ds_shipmentIndicationCommodity.getCellData(i, "shipTo")); // 


                        ds_orderCommodity.setCellData(oc_row, "wrkStDt", ed_wrkStDt.getValue()); // 작업시작일자
                        ds_orderCommodity.setCellData(oc_row, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                        ds_orderCommodity.setCellData(oc_row, "wrkEndDt", ed_wrkEndDt.getValue()); // 작업종료일자
                        ds_orderCommodity.setCellData(oc_row, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간

                        // 출발작업장코드, 도착작업장코드 자동 설정
                        ds_orderCommodity.setCellData(oc_row, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
                        ds_orderCommodity.setCellData(oc_row, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

                        // 영업담당자 정보 설정
                        if (i == 0) {
                            scwin.hid_salesPicNm = ds_shipmentIndicationCommodity.getCellData(i, "salesPicNm"); // 영업담당자명
                            scwin.hid_salesPicTelNo = ds_shipmentIndicationCommodity.getCellData(i, "salesPicTelNo"); // 영업담당자 전화번호
                            scwin.hid_tplPgmId = ds_shipmentIndicationCommodity.getCellData(i, "tplPgmId");   // 영업담당자 전화번호(ntis기준으로변경)
                        }

                        ds_orderCommodity.setCellData(i, "cnclYn" ,DsConstants.YN_NO ) ;

                    }
                }

                break;
            case DGauceConstants.TB_JOB_UPDATE: // UPDATE
                // 오더 품명 정보 설정
                if (ds_shipmentIndicationCommodity.getRowCount() > 0 && $c.gus.cfIsNull(ds_shipmentIndicationOrder.getCellData(ds_shipmentIndicationOrder.getRowPosition(), "mcomOdrNo"))) {
                    var count = 0;
                    for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount(); i++) {
                        count ++;
                        if (ds_shipmentIndicationCommodity.getCellData(i, "stsClsCd") == "I") {
                            // 품명 추가

                            //ds_orderCommodity.AddRow();
                            count++;
                            ds_orderCommodity.insertRow(ds_orderCommodity.getRowCount())//ds_orderCommodity.AddRow();
                            ds_orderCommodity.setRowPosition(ds_orderCommodity.getRowCount());
                            var oc_row = ds_orderCommodity.getRowPosition();

                            ds_orderCommodity.setCellData(oc_row, "odrNo", ds_order.getCellData(ds_order.getRowPosition(), "odrNo")); // 오더번호
                            ds_orderCommodity.setCellData(oc_row, "commSeq", count); // 품명순번
                            ds_orderCommodity.setCellData(oc_row, "commCd", ds_shipmentIndicationCommodity.getCellData(i, "commCd")); // 품명코드
                            ds_orderCommodity.setCellData(oc_row, "commNm", ds_shipmentIndicationCommodity.getCellData(i, "commNm")); // 품명
                            ds_orderCommodity.setCellData(oc_row, "qtyUnitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalQtyUnit")); // 단위코드 <- 내부 수량 단위
                            ds_orderCommodity.setCellData(oc_row, "unitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalWtUnit")); // 단위코드 <- 내부 중량 단위
                            ds_orderCommodity.setCellData(oc_row, "qty", ds_shipmentIndicationCommodity.getCellData(i, "qty")); // 수량
                            ds_orderCommodity.setCellData(oc_row, "grossWt", ds_shipmentIndicationCommodity.getCellData(i, "wt")); // 중량
                            ds_orderCommodity.setCellData(oc_row, "cstmrMgntNo", ds_shipmentIndicationCommodity.getCellData(i, "tplMgntNo")); // 고객관리번호 <- 관리번호
                            ds_orderCommodity.setCellData(oc_row, "mgntSeq", ds_shipmentIndicationCommodity.getCellData(i, "mgntSeq")); // 관리순번
                            ds_orderCommodity.setCellData(oc_row, "coCd", ds_shipmentIndicationCommodity.getCellData(i, "coCd")); // 회사코드
                            ds_orderCommodity.setCellData(oc_row, "bizLongCd", ds_shipmentIndicationCommodity.getCellData(i, "bizLongCd")); // 사업장코드
                            ds_orderCommodity.setCellData(oc_row, "tplArvNmCmpy", ds_shipmentIndicationCommodity.getCellData(i, "shipTo"));  // 

                            ds_orderCommodity.setCellData(oc_row, "wrkStDt", ed_wrkStDt.getValue()); // 작업시작일자
                            ds_orderCommodity.setCellData(oc_row, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                            ds_orderCommodity.setCellData(oc_row, "wrkEndDt", ed_wrkEndDt.getValue()); // 작업종료일자
                            ds_orderCommodity.setCellData(oc_row, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간

                            // 출발작업장코드, 도착작업장코드 자동 설정
                            ds_orderCommodity.setCellData(oc_row, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
                            ds_orderCommodity.setCellData(oc_row, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());

                            ds_orderCommodity.setCellData(oc_row, "cnclYn", DsConstants.YN_NO ) ;

                            // 영업담당자 정보 설정
                            if (i == 0) {
                                scwin.hid_salesPicNm = ds_shipmentIndicationCommodity.getCellData(i, "salesPicNm"); // 영업담당자명
                                scwin.hid_salesPicTelNo = ds_shipmentIndicationCommodity.getCellData(i, "salesPicTelNo"); // 영업담당자 전화번호
                                scwin.hid_tplPgmId = ds_shipmentIndicationCommodity.getCellData(i, "tplPgmId");  // 영업담당자 전화번호
                            }
                        } else if (ds_shipmentIndicationCommodity.getCellData(i, "stsClsCd") == "U") {

                            // 품명 데이터 셋에서 해당 품명을 찾아 정보를 변경
                            for (j = 0; j < ds_orderCommodity.getRowCount(); j++) {

                                if (ds_orderCommodity.getCellData(j, "commCd") == ds_shipmentIndicationCommodity.getCellData(i, "commCd")) { // 품명코드

                                    ds_orderCommodity.setCellData(j, "qtyUnitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalQtyUnit")); // 단위코드 <- 내부 수량 단위
                                    ds_orderCommodity.setCellData(j, "unitCd", ds_shipmentIndicationCommodity.getCellData(i, "internalWtUnit")); // 단위코드 <- 내부 중량 단위
                                    ds_orderCommodity.setCellData(j, "qty", ds_shipmentIndicationCommodity.getCellData(i, "qty")); // 수량
                                    ds_orderCommodity.setCellData(j, "grossWt", ds_shipmentIndicationCommodity.getCellData(i, "wt")); // 중량
                                    ds_orderCommodity.setCellData(j, "cstmrMgntNo", ds_shipmentIndicationCommodity.getCellData(i, "tplMgntNo")); // 고객관리번호 <- 관리번호
                                    ds_orderCommodity.setCellData(j, "mgntSeq", ds_shipmentIndicationCommodity.getCellData(i, "mgntSeq")); // 관리순번
                                    ds_orderCommodity.setCellData(j, "coCd", ds_shipmentIndicationCommodity.getCellData(i, "coCd")); // 회사코드
                                    ds_orderCommodity.setCellData(j, "bizLongCd", ds_shipmentIndicationCommodity.getCellData(i, "bizLongCd")); // 사업장코드
                                    ds_orderCommodity.setCellData(j, "tplArvNmCmpy", ds_shipmentIndicationCommodity.getCellData(i, "shipTo"));  // 

                                    ds_orderCommodity.setCellData(j, "wrkStDt", ed_wrkStDt.getValue()); // 작업시작일자
                                    ds_orderCommodity.setCellData(j, "wrkStHh", ed_wrkStHh.getValue()); // 작업시작시간
                                    ds_orderCommodity.setCellData(j, "wrkEndDt", ed_wrkEndDt.getValue()); // 작업종료일자
                                    ds_orderCommodity.setCellData(j, "wrkEndHh", ed_wrkEndHh.getValue()); // 작업종료시간

                                    // 출발작업장코드, 도착작업장코드 자동 설정
                                    ds_orderCommodity.setCellData(j, "dptWrkPlCd", ed_dptWrkPlCd.getValue().trim());
                                    ds_orderCommodity.setCellData(j, "arvWrkPlCd", ed_arvWrkPlCd.getValue().trim());
                                }
                            }

                        } else if (ds_shipmentIndicationCommodity.getCellData(i, "stsClsCd") == "D") {
                            // 품명 삭제

                            for (var j = 0; j < ds_orderCommodity.getRowCount(); j++) {

                                if (ds_orderCommodity.getCellData(j, "mgntSeq", ds_shipmentIndicationCommodity.getCellData(i, "mgntSeq"))) {
                                    ds_orderCommodity.setCellData(j, "cnclYn", DsConstants.YN_YES) ;
                                }
                            }
                        }
                    }
                }

                break;
            case DGauceConstants.TB_JOB_DELETE: // DELETE
                if (ds_shipmentIndicationCommodity.getCellData(i, "stsClsCd") == "D") {
                    // 품명 삭제
                    for (var j = 0; j < ds_orderCommodity.getRowCount(); j++) {
                        ds_orderCommodity.setCellData(j, "cnclYn", DsConstants.YN_YES) ;
                    }
                }
                break;
            default:
        }
    } catch (e) {
       console.log("f_setOrderCommodityInformation " + e);
    }
};

//-------------------------------------------------------------------------
// 계약번호 LuxeCombo 변경시
//-------------------------------------------------------------------------
scwin.acb_ctrtNo_onviewchange = async function (info) {
    try{
        let ctrtNo = "";
        let odrCtrtNo = "";
        let v_ctrtNo = "";
        let odrNo = "";
        let mgntTrgtClntYn = ""; //거래처 관리대상여부

        v_ctrtNo = acb_ctrtNo.getValue();//lc_ctrtNo.ValueOfIndex("ctrtNo", lc_ctrtNo.Index);
        ctrtNo = scwin.hid_ctrtNo;
        odrCtrtNo = scwin.hid_odrNo;
        odrNo = ed_mcomOdrNo.getValue();
        scwin.hid_taxnClsCd = ds_ctrtNo.getCellData(acb_ctrtNo.getSelectedIndex(), "taxnClsCd");//scwin.hid_taxnClsCd = ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "taxnClsCd");

	    if(ds_ctrtNo.getRowCount() > 0)	mgntTrgtClntYn = ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "mgntTrgtClntYn");

        // ntis기준으로변경
        if (acb_ctrtNo.getValue() != "선택") {
            await scwin.f_RetrieveCtrtWrkPath(acb_ctrtNo.getValue());
            // for (var i = 0; i < ds_shipmentIndicationCommodity.getRowCount() ; i++) {
            //     ds_shipmentIndicationCommodity.setCellData(i, "ctrtWrkPathSeq", 0);
            // }
        }

        if(mgntTrgtClntYn == "1"){
            $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_ERR_041,"본 계약거래처", "관리대상이므로 오더등록"));

            // DataSet 초기화
            scwin.acb_ctrtNo_check = "Y"; //TOBE 초기화시 화면데이터가 없어짐 현상유지용 처리 추가

            await scwin.f_clearDataSetAll();
            if(ds_order.getRowCount()==0) ds_order.insertRow(0); //기본 ds_order

            $c.gus.cfDisableKeyData();	
            $c.gus.cfDisableObjects([btn_Update, btn_Save, btn_Delete]);//cfDisableAllBtn();
            return false;
        }

        //TODO 확인필요. odrNo 당사오더번호
        if(v_ctrtNo != "" && ds_ctrtNo.getRowCount() > 0 && v_ctrtNo != ctrtNo && odrNo == ""){
            // 2. 계약번호 별 - 요청거래처, 실화주, 청구거래처 조회
		    scwin.f_clearClntDataSet();
		    scwin.hid_ctrtNo = v_ctrtNo;

            let acb_odrKndCdVal = "";
            let acb_mchtOdrKndCdVal = "";
            if (scwin.retrieveYn != "Y"){
               acb_odrKndCdVal = acb_odrKndCd.getValue() ;      
               acb_mchtOdrKndCdVal = acb_mchtOdrKndCd.getValue() ;
            }

            ds_order.setCellData(ds_order.getRowPosition(), "ctrtNo", v_ctrtNo);

            const params1 = {
                odrNo       : scwin.hid_odrNo , 
                ctrtNo      : acb_ctrtNo.getValue() ,
                ctrtClntNo  : scwin.hid_ctrtClntNo ,
                odrKndCd    : acb_odrKndCdVal ,
                bizDivCntrYn: scwin.hid_bizDivCntrYn ,
                bizDivBulkYn: scwin.hid_bizDivBulkYn ,
                //bizDivTplYn : scwin.hid_bizDivTplYn ,
                //transCargoClsCd : scwin.hid_transCargoClsCd ,
                //impExpDomesticClsCd : scwin.hid_impExpDomesticClsCd ,
            };
            //데이터셋에 정보설정
            ds_orderQueryCondition.setJSON(params1);
            console.log("계약번호 - 요청거래처, 청구거래처 1: " + ds_odrKndCd.getRowCount());
            let r = await $c.sbm.execute(sbm_retrieveCtrtNo);//계약번호 - 요청거래처, 청구거래처 조회
            if (r.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_retrieveCtrtNo_submitdone(r);
            }

            const params2 = {
                docCd   : scwin.hid_docCd , 
                clntNo  : scwin.hid_ctrtRepClntNo ,
                wrkPlCd : scwin.hid_wrkPlCd ,
                itemCd  : scwin.hid_itemCd ,
                osideCd : acb_mchtOdrKndCd.getValue() ,
                ctrtNo  : acb_ctrtNo.getValue() ,
            };
            ds_ediMappingSearch.setJSON(params2);
            let e = await $c.sbm.execute(sbm_reterieveOdrKndCd);
            if(e.responseJSON.resultDataSet[0].Code == -1) {
                await $c.win.alert(e.responseJSON.resultDataSet[1].Msg);
            } else if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                scwin.sbm_reterieveOdrKndCd_submitdone(e);
            }
            //$c.sbm.execute(sbm_reterieveOdrKndCd);//tr_reterieveOdrKndCd.post();
        }

    } catch (e) {
       console.log("acb_ctrtNo_onviewchange " + e);
    }
};

//-------------------------------------------------------------------------
// 오더종류 조회결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_reterieveOdrKndCd_submitdone = function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        if(ds_odrKndCd.getRowCount() == 0) {
            $c.gus.cfAlertMsg("거래처 "+ed_txt_clntNm.getValue()+"의 화주오더 종류 "+acb_mchtOdrKndCd.getValue()+"의 "+MSG_CM_ERR_049, "오더종류");
            return;
        }

        ds_odrKndCd.setJSON(e.responseJSON.OUT_DS1.sort((a, b) => {
            if (a.cd !== b.cd) {
                return a.cd.localeCompare(b.cd);
            }
            if (a.cdNm.length !== b.cdNm.length) {
                return a.cdNm.length - b.cdNm.length; 
            }
            return b.cdNm.localeCompare(a.cdNm);
        }));
    } catch (e) {
       console.log("sbm_reterieveOdrKndCd_submitdone " + e);
    }
};

//-------------------------------------------------------------------------
// 계약번호 - 요청거래처, 청구거래처 조회 결과 콜백
//-------------------------------------------------------------------------
scwin.sbm_retrieveCtrtNo_submitdone = async function(e) {
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail

        //for=ds_reqClntNo event=OnLoadCompleted(rowCnt)
        if (ds_reqClntNo.getRowCount() > 0) ds_reqClntNo.setRowPosition(0);
        ed_reqClntNo.setValue(ds_reqClntNo.getCellData(ds_reqClntNo.getRowPosition(), "clntNo"));
	    scwin.hid_chkReqClntNo = ds_reqClntNo.getCellData(ds_reqClntNo.getRowPosition(), "clntNo");

        //ds_bilgClntNo event=OnLoadCompleted(rowCnt)
        if (ds_bilgClntNo.getRowCount() > 0) ds_bilgClntNo.setRowPosition(0);
        if(ds_shipmentIndicationOrder.getCellData(0, "bizLongCd")=="5589" && ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(), "ctrtNo")!="선택"){

            if(await $c.win.confirm("청구거래처를 \'100258\' 로 설정하시겠습니까?")) {
                ed_bilgClntNo.setValue("100285");
                scwin.hid_chkBilgClntNo = "";
                scwin.f_bilgClntNo();
            }else{
                ed_bilgClntNo.setValue(ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo"));//ds_bilgClntNo.NameValue(ds_bilgClntNo.RowPosition, "clntNo");
                scwin.hid_chkBilgClntNo = ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo");
            }
        }else{
            ed_bilgClntNo.setValue(ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo"));//ds_bilgClntNo.NameValue(ds_bilgClntNo.RowPosition, "clntNo");
            scwin.hid_chkBilgClntNo = ds_bilgClntNo.getCellData(ds_bilgClntNo.getRowPosition(), "clntNo");
        }

    } catch (e) {
       console.log("sbm_retrieveCtrtNo_submitdone " + e);
    }
};


