scwin.ed_reqClntNo_onviewchange = function (e) {
    try{
        let pCode = "";
        let pName = "";

        pCode = ed_reqClntNo.getValue().replace(/^\s*/,''); 

        if(ed_reqClntNo.getReadOnly() == false) { 
            if (pCode != null && pCode != "" ) {

  			if ( pCode != scwin.hid_chkReqClntNo || $c.gus.cfIsNull(scwin.hid_chkReqClntNo) ){
  				scwin.f_openCommonPopUp(2, pCode, pName, 'T', 'T');
			}
            } else {
                ed_reqClntNo.setValue("");
                acb_reqClntNm.setSelectedIndex(-1);//lc_reqClntNm.index = -1;
            }
        }
    } catch (e) {
       console.log("ed_reqClntNo_onblur " + e);
    }
};

