scwin.f_Delete = async function() { 
    try{
        if(await $c.win.confirm($c.data.getMessage(MSG_CM_CRM_008, [scwin.hid_odrNo]))) {

            scwin.f_ds_orderSetting();//TOBE ds_order 정보 바인드 처리
            $c.sbm.execute(sbm_delete);
        }
    } catch (e) {
       console.log("f_Delete : " + e);
    } 
};

//-------------------------------------------------------------------------
// 삭제 콜백
//-------------------------------------------------------------------------
scwin.sbm_delete_submitdone = function(e) { 
    try{
        if (e.responseJSON.resultDataSet[0].Code < 0) return; //onFail
        $c.gus.cfAlertMsg($c.data.getMessage(MSG_CM_INF_011,[scwin.hid_odrNo]));// 삭제되었습니다.

        // 초기화
        scwin.f_defaultValue();

        // KeyData 비활성화
        $c.gus.cfDisableKeyData();

        // 그리드 행추가 / 삭제 /취소 버튼 비활성화
  	    $c.gus.cfDisableObjects([btn_Update, btn_Save, btn_Delete]);//cfDisableAllBtn();

    } catch (e) {
       console.log("sbm_delete_submitdone : " + e);
    } 
};

scwin.sbm_reterieveMchtOdrKnd2 = async function() {
    return await $c.sbm.execute(sbm_reterieveMchtOdrKnd2);
};

scwin.f_setSearchData = async function () { 
    if ($c.gus.cfIsNull(scwin.hid_odrNo.trim()))	scwin.hid_odrNo = scwin.mcomOdrNo;
    if ($c.gus.cfIsNull(scwin.hid_repClntNo.trim()))	scwin.hid_repClntNo = scwin.repClntNo;
    if ($c.gus.cfIsNull(scwin.hid_clntNo.trim()))	scwin.hid_clntNo = scwin.clntNo;
    if ($c.gus.cfIsNull(scwin.hid_clntNm.trim()))	scwin.hid_clntNm = scwin.clntNm;
    if ($c.gus.cfIsNull(scwin.hid_mchtOdrKndCd.trim()))	scwin.hid_mchtOdrKndCd = scwin.mchtOdrKndCd;
    if ($c.gus.cfIsNull(scwin.hid_mchtOdrKndNm.trim()))	scwin.hid_mchtOdrKndNm = scwin.mchtOdrKndNm;
    if ($c.gus.cfIsNull(scwin.hid_mchtOdrNo.trim()))	scwin.hid_mchtOdrNo = scwin.mchtOdrNo;
    if ($c.gus.cfIsNull(scwin.hid_mcomOdrNo.trim()))	scwin.hid_mcomOdrNo = scwin.mcomOdrNo;
    if ($c.gus.cfIsNull(scwin.hid_logSeq.trim()))	scwin.hid_logSeq = scwin.logSeq;
    if ($c.gus.cfIsNull(scwin.hid_chkReterieve.trim()))	scwin.hid_chkReterieve = scwin.type;

    if (!$c.gus.cfIsNull(scwin.hid_odrNo.trim())) {
        // 당사 오더 번호 설정시 조회
        if (scwin.hid_chkReterieve.trim() == "retrieve" && scwin.hid_chkReterieve.trim() != "retrieveIn") {
            ed_mcomOdrNo.setValue(scwin.hid_odrNo);
            await scwin.f_Retrieve();	// 오더 번호 존재시 조회 
        } else if (scwin.hid_chkReterieve != "retrieveIn") {
            ed_mcomOdrNo.setValue(scwin.hid_odrNo);
            await scwin.f_Retrieve();	// 오더 번호 존재시 조회 
        } else if (scwin.hid_odrNo.trim() != ed_mcomOdrNo.getValue().trim() && scwin.hid_chkReterieve.trim() == "retrieveIn") {
            ed_mcomOdrNo.setValue(scwin.hid_odrNo);
            await scwin.f_Retrieve();	// 오더 번호 존재시 조회 
        }
    } else if (!$c.gus.cfIsNull(scwin.hid_clntNo.trim()) && !$c.gus.cfIsNull(scwin.hid_mchtOdrKndCd.trim()) && !$c.gus.cfIsNull(scwin.hid_mchtOdrNo.trim())) {
        // 거래처, 화주어더종류, 화주오더번호 설정시 조회
        await scwin.f_setFrameOrderSearchQueryCondition();

        if (scwin.hid_chkReterieve.trim() == "retrieve" && scwin.hid_chkReterieve.trim() != "retrieveIn") {
            scwin.hid_ctrtRepClntNo = scwin.hid_repClntNo;
            ed_clntNo.setValue(scwin.hid_clntNo);
            ed_txt_clntNm.setValue(scwin.hid_clntNm);
            acb_mchtOdrKndCd.setValue(scwin.hid_mchtOdrKndCd);
            ed_mchtOdrNo.setValue(scwin.hid_mchtOdrNo);
            await scwin.f_Retrieve();	// 거래처번호, 화주오더종류, 화주오더번호 존재시 조회 
        } else if (scwin.hid_chkReterieve != "retrieveIn") {
            scwin.hid_ctrtRepClntNo = scwin.hid_repClntNo;
            ed_clntNo.setValue(scwin.hid_clntNo);
            ed_txt_clntNm.setValue(scwin.hid_clntNm);
            acb_mchtOdrKndCd.setValue(scwin.hid_mchtOdrKndCd);
            ed_mchtOdrNo.setValue(scwin.hid_mchtOdrNo);
            await scwin.f_Retrieve();	// 거래처번호, 화주오더종류, 화주오더번호 존재시 조회 
        } else if (scwin.hid_odrNo.trim() != ed_mcomOdrNo.getValue().trim() && scwin.hid_chkReterieve.trim() == "retrieveIn") {
            scwin.hid_ctrtRepClntNo = scwin.hid_repClntNo;
            ed_clntNo.setValue(scwin.hid_clntNo);
            ed_txt_clntNm.setValue(scwin.hid_clntNm);
            acb_mchtOdrKndCd.setValue(scwin.hid_mchtOdrKndCd);
            ed_mchtOdrNo.setValue(scwin.hid_mchtOdrNo);
            await scwin.f_Retrieve();	// 거래처번호, 화주오더종류, 화주오더번호 존재시 조회 
        }
    }		

    if (ds_mchtOdrKndCd.getRowCount() > 0) {
        acb_mchtOdrKndCd.setValue(scwin.hid_mchtOdrKndCd);
    } else {
        ds_mchtOdrKndCd.insertRow();
        ds_mchtOdrKndCd.setCellData(0, "osideCd", scwin.hid_mchtOdrKndCd);
        ds_mchtOdrKndCd.setCellData(0,"osideCdNm", scwin.hid_mchtOdrKndNm);
    }

    if (ds_shipmentIndicationOrder.getRowCount() > 0) {
        acb_logSeq.setValue(scwin.hid_logSeq);
    }

    btn_Retrieve.focus(); // onBlur 이벤트로 특정 컴포넌트로 변경되서 처리
};

// 오더요청 조회 조건 설정
scwin.f_setFrameOrderSearchQueryCondition = async function () { 
    scwin.hid_ctrtRepClntNo = scwin.hid_repClntNo;
    ed_clntNo.setValue(scwin.hid_clntNo);
    ed_txt_clntNm.setValue(scwin.hid_clntNm);
    if (!$c.gus.cfIsNull(scwin.hid_mchtOdrKndCd) && scwin.hid_chkReterieve == "retrieve") {
        if (scwin.hid_chkReterieve != "retrieveIn")	
            ds_ediMappingSearch.set("clntNo", scwin.hid_repClntNo);

            let e = await $c.sbm.execute(sbm_reterieveMchtOdrKnd2);
            if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
                if (ds_mchtOdrKndCd.getRowCount() > 0) {
                    acb_mchtOdrKndCd.setValue(scwin.hid_mchtOdrKndCd);
                } else {
                    ds_mchtOdrKndCd.insertRow();
                    ds_mchtOdrKndCd.setCellData(0, "osideCd", scwin.hid_mchtOdrKndCd);
                    ds_mchtOdrKndCd.setCellData(0, "osideCdNm", scwin.hid_mchtOdrKndNm);
                }
            }
    } else {
        acb_mchtOdrKndCd.setValue("");
    }

    ed_mchtOdrNo.setValue(scwin.hid_mchtOdrNo);
    ed_mcomOdrNo.setValue(scwin.hid_mcomOdrNo);
};

