scwin.f_RetrieveCtrtWrkPath = async function (ctrtNo) {
    ds_ctrtWrkPath.removeAll();
    sbm_ctrtWrkPath.action = "/cm.zz.RetrieveComboCMD.do?sysCd=BulkOrderEBC&queryId=retrieveContractWorkPathComboList&param1=" + ctrtNo + "&param2=" + acb_odrKndCd.getValue();
    let e = await $c.sbm.execute(sbm_ctrtWrkPath);
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC") {
        scwin.sbm_ctrtWrkPath_submitdone(e);
    }
};

scwin.sbm_ctrtWrkPath_submitdone = async function (e) {
    var rowIndex = ds_ctrtWrkPath.insertRow(0);
    ds_ctrtWrkPath.setRowPosition(rowIndex);
    ds_ctrtWrkPath.setCellData(rowIndex, 'ctrtWrkPathSeq', 0);
    ds_ctrtWrkPath.setCellData(rowIndex, 'ctrtWrkPathNm', "선택");

    if (!$c.gus.cfIsNull(acb_ctrtNo.getValue())) {
        gr_shipmentIndicationCommodityList.refreshColumn('ctrtWrkPathSeq'); 
    }
};

