}

scwin.truncateBy40Byte = (str) => {
    let currentByte = 0;
    let truncatedStr = "";
    for (let i = 0; i < str.length; i++) {
        const char = str[i];
        const charByte = str.charCodeAt(i) > 128 ? 2 : 1;
        if (currentByte + charByte > 40) {
            break;
        }
        currentByte += charByte;
        truncatedStr += char;
    }
    return truncatedStr;
};
